import { useState, useEffect, useCallback, useMemo } from 'react';
import { getApiBase } from '../utils/platform';
import { tokens } from '../styles/tokens';
import GlassPanel from '../components/ui/GlassPanel';
import StatCard from '../components/ui/StatCard';
import usePageTitle from '../hooks/usePageTitle';
import s from './StrategyGenomePage.module.css';

const T = {
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple,
  text: tokens.color.text, textSec: tokens.color.textSecondary,
  surface2: tokens.color.surfaceHover,
};

const FAMILY_META = {
  momentum: { color: T.green, icon: '\u2197', desc: 'Trend-following strategies that exploit directional price momentum' },
  mean_reversion: { color: T.blue, icon: '\u21C4', desc: 'Strategies that profit from price returning to its mean' },
  breakout: { color: T.amber, icon: '\u26A1', desc: 'Strategies that identify and trade price level breakthroughs' },
  trend_following: { color: T.purple, icon: '\u2192', desc: 'Long-horizon strategies riding established market trends' },
  volatility: { color: T.red, icon: '\u2248', desc: 'Strategies exploiting volatility patterns and mean reversion' },
  statistical_arb: { color: '#39D2C0', icon: '\u0394', desc: 'Quantitative strategies based on statistical relationships' },
  macro: { color: '#E879F9', icon: '\u2605', desc: 'Top-down strategies driven by macroeconomic signals' },
  crypto_native: { color: '#F97316', icon: '\u20BF', desc: 'Strategies designed specifically for cryptocurrency markets' },
};

function FamilyCard({ family, strategies, expanded, onToggle }) {
  const meta = FAMILY_META[family] || { color: T.blue, icon: '?', desc: '' };
  const count = strategies.length;
  const avgSharpe = count ? (strategies.reduce((sum, st) => sum + (st.sharpe || 0), 0) / count).toFixed(2) : '--';
  const avgWR = count ? ((strategies.reduce((sum, st) => sum + (st.win_rate || 0), 0) / count) * 100).toFixed(1) + '%' : '--';

  return (
    <GlassPanel className={s.familyOverflow}>
      <div onClick={onToggle} className={s.familyHeader}>
        <span className={s.familyIcon} style={{ background: meta.color + '18' }}>
          {meta.icon}
        </span>
        <div className={s.familyInfo}>
          <div className={s.familyName}>{family.replace(/_/g, ' ')}</div>
          <div className={s.familyDesc}>{meta.desc}</div>
        </div>
        <div className={s.familyMetrics}>
          <div className={s.metricCell}>
            <div className={s.metricValue} style={{ color: meta.color }}>{count}</div>
            <div className={s.metricLabel}>strategies</div>
          </div>
          <div className={s.metricCell}>
            <div className={s.metricValueSm}>{avgSharpe}</div>
            <div className={s.metricLabel}>avg sharpe</div>
          </div>
          <div className={s.metricCell}>
            <div className={s.metricValueSm}>{avgWR}</div>
            <div className={s.metricLabel}>avg WR</div>
          </div>
          <span className={`${s.chevron} ${expanded ? s.chevronExpanded : ''}`}>
            &#9660;
          </span>
        </div>
      </div>

      {expanded && strategies.length > 0 && (
        <div className={s.expandedSection}>
          <table className={s.strategyTable}>
            <thead>
              <tr>
                {['Strategy', 'Direction', 'Sharpe', 'Win Rate', 'Profit Factor', 'Trades', 'Status'].map(h => (
                  <th key={h} className={s.tableHeader}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {strategies.map((st, i) => (
                <tr key={st.name || i} className={s.tableRow}>
                  <td className={s.cellName}>{st.name}</td>
                  <td className={s.tableCell}>
                    <span className={s.directionBadge} style={{
                      background: (st.direction === 'LONG' || st.direction === 'long') ? T.green + '18' : T.red + '18',
                      color: (st.direction === 'LONG' || st.direction === 'long') ? T.green : T.red,
                    }}>
                      {(st.direction || 'LONG').toUpperCase()}
                    </span>
                  </td>
                  <td className={s.tableCell} style={{ color: (st.sharpe || 0) >= 1 ? T.green : T.amber }}>
                    {st.sharpe != null ? Number(st.sharpe).toFixed(2) : '--'}
                  </td>
                  <td className={s.cellText}>
                    {st.win_rate != null ? (Number(st.win_rate) * 100).toFixed(1) + '%' : '--'}
                  </td>
                  <td className={s.cellText}>
                    {st.profit_factor != null ? Number(st.profit_factor).toFixed(2) : '--'}
                  </td>
                  <td className={s.cellText}>{st.trades ?? '--'}</td>
                  <td className={s.tableCell}>
                    <span className={s.statusBadge} style={{
                      background: st.status === 'LIVE' ? T.green + '18' : st.status === 'PAPER' ? T.amber + '18' : T.surface2,
                      color: st.status === 'LIVE' ? T.green : st.status === 'PAPER' ? T.amber : T.textSec,
                    }}>
                      {st.status || 'BACKTEST'}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </GlassPanel>
  );
}

export default function StrategyGenomePage() {
  usePageTitle('Strategy Genome');
  const [strategies, setStrategies] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [expandedFamilies, setExpandedFamilies] = useState(new Set());

  const fetchData = useCallback(async () => {
    try {
      const res = await fetch(`${getApiBase()}/strategies`);
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const json = await res.json();
      setStrategies(json.strategies || json || []);
      setError(null);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchData(); }, [fetchData]);

  const familyGroups = useMemo(() => {
    const groups = {};
    strategies.forEach(st => {
      const fam = st.family || st.genome_family || 'unknown';
      if (!groups[fam]) groups[fam] = [];
      groups[fam].push(st);
    });
    return Object.entries(groups).sort((a, b) => b[1].length - a[1].length);
  }, [strategies]);

  const toggleFamily = (fam) => {
    setExpandedFamilies(prev => {
      const next = new Set(prev);
      if (next.has(fam)) next.delete(fam); else next.add(fam);
      return next;
    });
  };

  if (loading) {
    return <div className={s.loading}>Loading genome data...</div>;
  }

  return (
    <div className={s.page}>
      <h1 className={s.title}>Strategy Genome Browser</h1>
      <p className={s.subtitle}>
        Browse 8 genome families and their member strategies — click to expand
      </p>

      {error && (
        <GlassPanel className={s.errorPanel}>
          <div className={s.errorText}>Error: {error}</div>
        </GlassPanel>
      )}

      {/* Summary stats */}
      <div className={s.statsGrid}>
        <StatCard label="Total Strategies" value={strategies.length} color={T.blue} />
        <StatCard label="Genome Families" value={familyGroups.length} color={T.purple} />
        <StatCard label="Largest Family" value={familyGroups[0]?.[0]?.replace(/_/g, ' ') || '--'}
          subtitle={`${familyGroups[0]?.[1]?.length || 0} strategies`} color={T.green} />
      </div>

      {/* Family cards */}
      <div className={s.familyList}>
        {familyGroups.map(([family, strats]) => (
          <FamilyCard
            key={family}
            family={family}
            strategies={strats}
            expanded={expandedFamilies.has(family)}
            onToggle={() => toggleFamily(family)}
          />
        ))}
      </div>

      {familyGroups.length === 0 && !error && (
        <GlassPanel className={s.emptyPanel}>
          <div className={s.emptyText}>No genome data available</div>
        </GlassPanel>
      )}
    </div>
  );
}
